  rpc LookupProductById(LookupProductByIdRequest) returns (LookupProductByIdResponse) {}
  rpc QueryReview(QueryReviewRequest) returns (QueryReviewResponse) {}
}

// Wrapper message for a list of Review.
message ListOfReview {
  message List {
    repeated Review items = 1;
  }
  List list = 1;
