message QueryReviewRequest {
  string id = 1;
}
// Response message for review operation.
message QueryReviewResponse {
  Review review = 1;
}

// Entity describing a product with reviews
message Product {
  string id = 1;
  ListOfReview reviews = 2;
}

// Review entity
message Review {
  string id = 1;
  string author = 2;
  string email = 3;
  int32 created_on = 4;
  google.protobuf.StringValue contents = 5;
  int32 rating = 6;
}

